import type { KbdProps as _KbdProps } from '@soybeanjs/headless/kbd';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { KbdVariant } from '@/styles/kbd';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Kbd component.
 */
export interface KbdProps extends _KbdProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Visual variant of the component.
   */
  variant?: KbdVariant;
  /**
   * Whether raised.
   */
  raised?: boolean;
}

export type { KbdVariant };

// @unocss-include
import { cv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const kbdVariants = cv({
  base: `inline-flex items-center justify-center w-fit text-center font-medium border border-border rounded-sm font-inherit`,
  variants: {
    variant: {
      solid: 'border-muted-foreground bg-muted-foreground text-muted shadow-muted-foreground/50',
      outline: 'border-border bg-background text-muted-foreground shadow-border',
      ghost: 'border-border bg-muted text-muted-foreground shadow-border/50'
    },
    size: {
      xs: 'h-4 min-w-4 px-0.5 text-3xs data-[group]:tracking-0.5',
      sm: 'h-4.5 min-w-4.5 px-0.625 text-2xs data-[group]:tracking-0.625',
      md: 'h-5 min-w-5 px-0.75 text-xs data-[group]:tracking-0.75',
      lg: 'h-6 min-w-6 px-1 text-sm data-[group]:tracking-1',
      xl: 'h-7 min-w-7 px-1.25 text-base data-[group]:tracking-1.25',
      '2xl': 'h-8 min-w-8 px-1.5 text-xl data-[group]:tracking-1.5'
    },
    raised: {
      true: 'shadow-[0_2px_0_0]'
    }
  },
  defaultVariants: {
    size: 'md',
    variant: 'outline',
    raised: true
  }
});

type KbdVariants = VariantProps<typeof kbdVariants>;

export type KbdVariant = NonNullable<KbdVariants['variant']>;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
